  = NexusOperationIdReusePolicy'NexusOperationIdReusePolicyUnspecified
  | NexusOperationIdReusePolicy'NexusOperationIdReusePolicyAllowDuplicate
    -- ^ Always allow starting an operation using the same operation ID.
  | NexusOperationIdReusePolicy'NexusOperationIdReusePolicyAllowDuplicateFailedOnly
    -- ^ Allow starting an operation using the same ID only when the last operation's final state is one
    -- of {failed, canceled, terminated, timed out}.
  | NexusOperationIdReusePolicy'NexusOperationIdReusePolicyRejectDuplicate
    -- ^ Do not permit re-use of the ID for this operation. Future start requests could potentially change the policy,
    -- allowing re-use of the ID.
  deriving stock (Show, Eq, Ord, Enum, Bounded, Generic)
  deriving anyclass NFData

toProtoEnumNexusOperationIdReusePolicy :: NexusOperationIdReusePolicy -> Int
toProtoEnumNexusOperationIdReusePolicy NexusOperationIdReusePolicy'NexusOperationIdReusePolicyUnspecified = 0
toProtoEnumNexusOperationIdReusePolicy NexusOperationIdReusePolicy'NexusOperationIdReusePolicyAllowDuplicate = 1
toProtoEnumNexusOperationIdReusePolicy NexusOperationIdReusePolicy'NexusOperationIdReusePolicyAllowDuplicateFailedOnly = 2
toProtoEnumNexusOperationIdReusePolicy NexusOperationIdReusePolicy'NexusOperationIdReusePolicyRejectDuplicate = 3

fromProtoEnumNexusOperationIdReusePolicy :: Int -> Maybe NexusOperationIdReusePolicy
fromProtoEnumNexusOperationIdReusePolicy 0 = Just NexusOperationIdReusePolicy'NexusOperationIdReusePolicyUnspecified
fromProtoEnumNexusOperationIdReusePolicy 1 = Just NexusOperationIdReusePolicy'NexusOperationIdReusePolicyAllowDuplicate
fromProtoEnumNexusOperationIdReusePolicy 2 = Just NexusOperationIdReusePolicy'NexusOperationIdReusePolicyAllowDuplicateFailedOnly
fromProtoEnumNexusOperationIdReusePolicy 3 = Just NexusOperationIdReusePolicy'NexusOperationIdReusePolicyRejectDuplicate
fromProtoEnumNexusOperationIdReusePolicy _ = Nothing

