  toJSON NexusOperationIdReusePolicy'NexusOperationIdReusePolicyAllowDuplicate = Aeson.String "NEXUS_OPERATION_ID_REUSE_POLICY_ALLOW_DUPLICATE"
  toJSON NexusOperationIdReusePolicy'NexusOperationIdReusePolicyAllowDuplicateFailedOnly = Aeson.String "NEXUS_OPERATION_ID_REUSE_POLICY_ALLOW_DUPLICATE_FAILED_ONLY"
  toJSON NexusOperationIdReusePolicy'NexusOperationIdReusePolicyRejectDuplicate = Aeson.String "NEXUS_OPERATION_ID_REUSE_POLICY_REJECT_DUPLICATE"

