  parseJSON = \case
    Aeson.String "NEXUS_OPERATION_ID_REUSE_POLICY_UNSPECIFIED" -> pure NexusOperationIdReusePolicy'NexusOperationIdReusePolicyUnspecified
    Aeson.String "NEXUS_OPERATION_ID_REUSE_POLICY_ALLOW_DUPLICATE" -> pure NexusOperationIdReusePolicy'NexusOperationIdReusePolicyAllowDuplicate
    Aeson.String "NEXUS_OPERATION_ID_REUSE_POLICY_ALLOW_DUPLICATE_FAILED_ONLY" -> pure NexusOperationIdReusePolicy'NexusOperationIdReusePolicyAllowDuplicateFailedOnly
    Aeson.String "NEXUS_OPERATION_ID_REUSE_POLICY_REJECT_DUPLICATE" -> pure NexusOperationIdReusePolicy'NexusOperationIdReusePolicyRejectDuplicate
    Aeson.Number n -> pure (toEnum (round n))
    _ -> fail "Invalid enum value for NexusOperationIdReusePolicy"

