-- | Defines what to do when trying to start a Nexus operation with the same ID as a *running* operation.
-- Note that it is *never* valid to have two running instances of the same operation ID.
-- 
-- See `NexusOperationIdReusePolicy` for handling operation ID duplication with a *closed* operation.
data NexusOperationIdConflictPolicy
  = NexusOperationIdConflictPolicy'NexusOperationIdConflictPolicyUnspecified
  | NexusOperationIdConflictPolicy'NexusOperationIdConflictPolicyFail
    -- ^ Don't start a new operation; instead return `NexusOperationAlreadyStarted` error.
  | NexusOperationIdConflictPolicy'NexusOperationIdConflictPolicyUseExisting
    -- ^ Don't start a new operation; instead return a handle for the running operation.
  deriving stock (Show, Eq, Ord, Enum, Bounded, Generic)
  deriving anyclass NFData

toProtoEnumNexusOperationIdConflictPolicy :: NexusOperationIdConflictPolicy -> Int
toProtoEnumNexusOperationIdConflictPolicy NexusOperationIdConflictPolicy'NexusOperationIdConflictPolicyUnspecified = 0
toProtoEnumNexusOperationIdConflictPolicy NexusOperationIdConflictPolicy'NexusOperationIdConflictPolicyFail = 1
toProtoEnumNexusOperationIdConflictPolicy NexusOperationIdConflictPolicy'NexusOperationIdConflictPolicyUseExisting = 2

fromProtoEnumNexusOperationIdConflictPolicy :: Int -> Maybe NexusOperationIdConflictPolicy
fromProtoEnumNexusOperationIdConflictPolicy 0 = Just NexusOperationIdConflictPolicy'NexusOperationIdConflictPolicyUnspecified
fromProtoEnumNexusOperationIdConflictPolicy 1 = Just NexusOperationIdConflictPolicy'NexusOperationIdConflictPolicyFail
fromProtoEnumNexusOperationIdConflictPolicy 2 = Just NexusOperationIdConflictPolicy'NexusOperationIdConflictPolicyUseExisting
fromProtoEnumNexusOperationIdConflictPolicy _ = Nothing

